# --- Service Clients (lazy initialization) ---

class ServiceClients:
    """Lazy-initialized service clients using managed identity."""

    _blob_client: Optional[BlobServiceClient] = None
    _cosmos_client: Optional[CosmosClient] = None
    _eventgrid_client: Optional[EventGridPublisherClient] = None

    @classmethod
    def get_blob_client(cls) -> BlobServiceClient:
        if cls._blob_client is None:
            cls._blob_client = BlobServiceClient(
                account_url=Config.STORAGE_ACCOUNT_URL,
                credential=CredentialManager.get_credential(),
            )
        return cls._blob_client

    @classmethod
    def get_cosmos_client(cls) -> CosmosClient:
        if cls._cosmos_client is None:
            cls._cosmos_client = CosmosClient(
                url=Config.COSMOS_ENDPOINT,
                credential=CredentialManager.get_credential(),
            )
        return cls._cosmos_client

    @classmethod
    def get_cosmos_container(cls):
        client = cls.get_cosmos_client()
        database = client.get_database_client(Config.COSMOS_DATABASE_NAME)
        return database.get_container_client(Config.COSMOS_CONTAINER_NAME)

    @classmethod
    def get_eventgrid_client(cls) -> EventGridPublisherClient:
        if cls._eventgrid_client is None:
            cls._eventgrid_client = EventGridPublisherClient(
                endpoint=Config.EVENT_GRID_TOPIC_ENDPOINT,
                credential=CredentialManager.get_credential(),
            )
        return cls._eventgrid_client


# --- Input Validation ---

class InputValidator:
    """Validates and sanitizes all inputs to prevent injection and abuse."""

    @staticmethod
    def validate_blob_path(container_name: str, blob_name: str) -> tuple[bool, str]:
        """Validate blob path to prevent path traversal and unauthorized access."""
        # Check container is in allowlist
        if container_name not in Config.ALLOWED_CONTAINERS:
            return False, f"Container '{container_name}' is not in the allowed list"

        # Prevent path traversal
        if ".." in blob_name or blob_name.startswith("/"):
            return False, f"Invalid blob path detected: {blob_name}"

        # Check file extension
        _, ext = os.path.splitext(blob_name.lower())
        if ext not in Config.ALLOWED_EXTENSIONS:
            return False, f"File extension '{ext}' is not allowed"

        # Validate blob name length
        if len(blob_name) > 1024:
            return False, "Blob name exceeds maximum length"

        return True, "Valid"

    @staticmethod
    def validate_file_size(size_bytes: int) -> tuple[bool, str]:
        """Validate file size to prevent resource exhaustion."""
        if size_bytes > Config.MAX_FILE_SIZE_BYTES:
            return False, (
                f"File size {size_bytes} exceeds maximum "
                f"allowed size {Config.MAX_FILE_SIZE_BYTES}"
            )
        if size_bytes == 0:
            return False, "File is empty"
        return True, "Valid"

    @staticmethod
    def sanitize_for_cosmos(data: dict) -> dict:
        """Sanitize data before writing to Cosmos DB."""
        sanitized = {}
        for key, value in data.items():
            # Ensure keys are safe strings
            safe_key = str(key).strip()[:256]
            if isinstance(value, str):
                # Limit string length to prevent storage abuse
                sanitized[safe_key] = value[:10000]
            elif isinstance(value, (int, float, bool)):
                sanitized[safe_key] = value
            elif isinstance(value, dict):
                sanitized[safe_key] = InputValidator.sanitize_for_cosmos(value)
            elif isinstance(value, list):
                # Limit list size
                sanitized[safe_key] = value[:1000]
            else:
                sanitized[safe_key] = str(value)[:10000]
        return sanitized


# --- File Processing Logic ---

class FileProcessor:
    """Processes blob files and returns structured results."""

    @staticmethod
    def process_file(blob_name: str, content: bytes) -> dict:
        """
        Process file content and return results.
        Replace this with your actual business logic.
        """
        _, ext = os.path.splitext(blob_name.lower())

        # Calculate content hash for integrity verification
        content_hash = hashlib.sha256(content).hexdigest()

        result = {
            "file_name": os.path.basename(blob_name),
            "file_extension": ext,
            "file_size_bytes": len(content),
            "content_hash_sha256": content_hash,
            "processed_at": datetime.now(timezone.utc).isoformat(),
            "status": "processed",
        }

        if ext == ".json":
            try:
                parsed = json.loads(content.decode("utf-8"))
                result["record_count"] = (
                    len(parsed) if isinstance(parsed, list) else 1
                )
                result["parsing_status"] = "success"
            except (json.JSONDecodeError, UnicodeDecodeError) as e:
                result["parsing_status"] = "failed"
                result["parsing_error"] = str(e)[:500]
                result["status"] = "processed_with_errors"

        elif ext == ".csv":
            try:
                text = content.decode("utf-8")
                lines = text.strip().split("\n")
                result["line_count"] = len(lines)
                result["record_count"] = max(0, len(lines) - 1)  # Exclude header
                result["parsing_status"] = "success"
            except UnicodeDecodeError as e:
                result["parsing_status"] = "failed"
                result["parsing_error"] = str(e)[:500]
                result["status"] = "processed_with_errors"

        elif ext == ".txt":
            try:
                text = content.decode("utf-8")
                result["line_count"] = len(text.strip().split("\n"))
                result["character_count"] = len(text)
                result["parsing_status"] = "success"
            except UnicodeDecodeError as e:
                result["parsing_status"] = "failed"
                result["parsing_error"] = str(e)[:500]
                result["status"] = "processed_with_errors"

        else:
            result["parsing_status"] = "skipped"
            result["status"] = "processed_no_parsing"

        return result


# --- Cosmos DB Writer ---

class CosmosWriter:
    """Writes processing results to Cosmos DB with proper error handling."""

    @staticmethod
    def write_result(
        container_name: str, blob_name: str, processing_result: dict
    ) -> dict:
        """Write a processing result document to Cosmos DB."""
        # Create a deterministic document ID
        doc_id = hashlib.sha256(
            f"{container_name}/{blob_name}".encode()
        ).hexdigest()[:36]

        document = {
            "id": doc_id,
            "partitionKey": container_name,
            "source_container": container_name,
            "source_blob": blob_name,
            "processing_result": InputValidator.sanitize_for_cosmos(processing_result),
            "created_at": datetime.now(timezone.utc).isoformat(),
            "ttl": 90 * 24 * 3600,  # 90-day TTL to prevent unbounded growth
        }

        container = ServiceClients.get_cosmos_container()
        response = container.upsert_item(body=document)

        logger.info(
            "Document written to Cosmos DB",
            extra={"document_id": doc_id, "container": container_name},
        )
        return response


# --- Event Grid Notifier ---

class EventGridNotifier:
    """Sends processing notifications via Event Grid."""

    @staticmethod
    def send_notification(
        container_name: str,
        blob_name: str,
        status: str,
        summary: dict,
    ) -> None:
        """Send a processing completion event to Event Grid."""
        # Only include non-sensitive metadata in events
        event_data = {
            "source_container": container_name,
            "source_blob": os.path.basename(blob_name),  # Only filename, not full path
            "status": status,
            "processed_at": datetime.now(timezone.utc).isoformat(),
            "record_count": summary.get("record_count"),
            "file_size_bytes": summary.get("file_size_bytes"),
        }

        event = CloudEvent(
            source=f"/azure/functions/file-processor/{container_name}",
            type="FileProcessing.Completed",
            data=event_data,
            subject=f"files/{os.path.basename(blob_name)}",
        )

        client = ServiceClients.get_eventgrid_client()
        client.send([event])

        logger.info(
            "Event Grid notification sent",
            extra={"blob": blob_name, "status": status},
        )


# --- Azure Function Entry Points ---

@app.blob_trigger(
    arg_name="myblob",
    path="input-files/{name}",
    connection="STORAGE_CONNECTION",  # Uses managed identity via connection string setting
)
def process_blob(myblob: func.InputStream):
    """
    Blob-triggered function that processes uploaded files.

    Security measures:
    1. Input validation (path, size, extension)
    2. Managed identity authentication (no stored secrets)
    3. Sanitized outputs to Cosmos DB
    4. Non-sensitive event notifications
    5. Structured logging without sensitive data
    """
    blob_name = myblob.name or ""
    blob_uri = myblob.uri or ""

    logger.info(
        "Blob trigger activated",
        extra={
            "blob_name": blob_name,
            "blob_length": myblob.length,
        },
    )

    # --- Step 0: Validate configuration ---
    config_errors = Config.validate()
    if config_errors:
        logger.error(
            "Configuration validation failed",
            extra={"errors": config_errors},
        )
        raise RuntimeError(f"Configuration errors: {config_errors}")

    # --- Step 1: Parse and validate blob path ---
    # blob_name format: "container-name/path/to/file.ext"
    parts = blob_name.split("/", 1)
    if len(parts) != 2:
        logger.error("Invalid blob path format", extra={"blob_name": blob_name})
        return

    container_name, file_path = parts[0], parts[1]

    is_valid, message = InputValidator.validate_blob_path(container_name, file_path)
    if not is_valid:
        logger.warning(
            "Blob path validation failed",
            extra={"blob_name": blob_name, "reason": message},
        )
        return

    # --- Step 2: Validate file size ---
    file_size = myblob.length or 0
    is_valid, message = InputValidator.validate_file_size(file_size)
    if not is_valid:
        logger.warning(
            "File size validation failed",
            extra={"blob_name": blob_name, "size": file_size, "reason": message},
        )
        # Still notify about the rejection
        try:
            EventGridNotifier.send_notification(
                container_name=container_name,
                blob_name=file_path,
                status="rejected",
                summary={"reason": message, "file_size_bytes": file_size},
            )
        except Exception as notify_err:
            logger.error(
                "Failed to send rejection notification",
                extra={"error": str(notify_err)},
            )
        return

    # --- Step 3: Read and process the file ---
    try:
        content = myblob.read()
        logger.info(
            "File content read successfully",
            extra={"blob_name": blob_name, "content_length": len(content)},
        )
    except Exception as read_err:
        logger.error(
            "Failed to read blob content",
            extra={"blob_name": blob_name, "error": str(read_err)},
        )
        raise

    try:
        processing_result = FileProcessor.process_file(file_path, content)
        logger.info(
            "File processed successfully",
            extra={
                "blob_name": blob_name,
                "status": processing_result.get("status"),
            },
        )
    except Exception as proc_err:
        logger.error(
            "File processing failed",
            extra={"blob_name": blob_name, "error": str(proc_err)},
        )
        processing_result = {
            "status": "failed",
            "error": str(proc_err)[:500],
            "processed_at": datetime.now(timezone.utc).isoformat(),
        }

    # --- Step 4: Write results to Cosmos DB ---
    try:
        CosmosWriter.write_result(container_name, file_path, processing_result)
    except Exception as cosmos_err:
        logger.error(
            "Failed to write to Cosmos DB",
            extra={"blob_name": blob_name, "error": str(cosmos_err)},
        )
        # Don't re-raise - still try to send notification
        processing_result["cosmos_write_status"] = "failed"

    # --- Step 5: Send Event Grid notification ---
    try:
        EventGridNotifier.send_notification(
            container_name=container_name,
            blob_name=file_path,
            status=processing_result.get("status", "unknown"),
            summary=processing_result,
        )
    except Exception as eg_err:
        logger.error(
            "Failed to send Event Grid notification",
            extra={"blob_name": blob_name, "error": str(eg_err)},
        )

    logger.info(
        "Blob processing pipeline completed",
        extra={
            "blob_name": blob_name,
            "final_status": processing_result.get("status"),
        },
    )


# --- HTTP-triggered health check endpoint ---

@app.route(route="health", auth_level=func.AuthLevel.FUNCTION)
def health_check(req: func.HttpRequest) -> func.HttpResponse:
    """
    Health check endpoint to verify function and dependencies are operational.
    Protected by function-level auth key.
    """
    health_status = {
        "status": "healthy",
        "timestamp": datetime.now(timezone.utc).isoformat(),
        "checks": {},
    }

    # Check configuration
    config_errors = Config.validate()
    health_status["checks"]["configuration"] = {
        "status": "pass" if not config_errors else "fail",
        "errors": config_errors if config_errors else None,
    }

    # Check Cosmos DB connectivity
    try:
        container = ServiceClients.get_cosmos_container()
        # Read container properties to verify connectivity
        container.read()
        health_status["checks"]["cosmos_db"] = {"status": "pass"}
    except Exception as e:
        health_status["checks"]["cosmos_db"] = {
            "status": "fail",
            "error": str(e)[:200],
        }
        health_status["status"] = "degraded"

    # Check Blob Storage connectivity
    try:
        blob_client = ServiceClients.get_blob_client()
        # List containers to verify connectivity (limited to 1)
        next(blob_client.list_containers(results_per_page=1), None)
        health_status["checks"]["blob_storage"] = {"status": "pass"}
    except Exception as e:
        health_status["checks"]["blob_storage"] = {
            "status": "fail",
            "error": str(e)[:200],
        }
        health_status["status"] = "degraded"

    status_code = 200 if health_status["status"] == "healthy" else 503

    return func.HttpResponse(
        body=json.dumps(health_status, indent=2),
        status_code=status_code,
        mimetype="application/json",
    )


# --- HTTP-triggered manual processing endpoint ---

@app.route(route="process", methods=["POST"], auth_level=func.AuthLevel.FUNCTION)
def manual_process(req: func.HttpRequest) -> func.HttpResponse:
    """
    HTTP endpoint to manually trigger processing of a specific blob.
    Protected by function-level auth key.

    Request body:
    {
        "container": "input-files",
        "blob_path": "path/to/file.csv"
    }
    """
    try:
        req_body = req.get_json()
    except ValueError:
        return func.HttpResponse(
            json.dumps({"error": "Invalid JSON in request body"}),
            status_code=400,
            mimetype="application/json",
        )

    container_name = req_body.get("container", "")
    blob_path = req_body.get("blob_path", "")

    if not container_name or not blob_path:
        return func.HttpResponse(
            json.dumps({"error": "Both 'container' and 'blob_path' are required"}),
            status_code=400,
            mimetype="application/json",
        )

    # Validate inputs
    is_valid, message = InputValidator.validate_blob_path(container_name, blob_path)
    if not is_valid:
        return func.HttpResponse(
            json.dumps({"error": f"Validation failed: {message}"}),
            status_code=400,
            mimetype="application/json",
        )

    try:
        # Read blob using managed identity
        blob_client = ServiceClients.get_blob_client()
        blob = blob_client.get_blob_client(container=container_name, blob=blob_path)

        # Check blob properties first
        properties = blob.get_blob_properties()
        is_valid, message = InputValidator.validate_file_size(properties.size)
        if not is_valid:
            return func.HttpResponse(
                json.dumps({"error": f"File size validation failed: {message}"}),
                status_code=400,
                mimetype="application/json",
            )

        # Download and process
        content = blob.download_blob().readall()
        processing_result = FileProcessor.process_file(blob_path, content)

        # Write to Cosmos DB
        CosmosWriter.write_result(container_name, blob_path, processing_result)

        # Send notification
        EventGridNotifier.send_notification(
            container_name=container_name,
            blob_name=blob_path,
            status=processing_result.get("status", "unknown"),
            summary=processing_result,
        )

        return func.HttpResponse(
            json.dumps({
                "status": "success",
                "result": processing_result,
            }, indent=2),
            status_code=200,
            mimetype="application/json",
        )

    except Exception as e:
        logger.error(
            "Manual processing failed",
            extra={"container": container_name, "blob": blob_path, "error": str(e)},
        )
        return func.HttpResponse(
            json.dumps({"error": "Processing failed", "details": str(e)[:500]}),
            status_code=500,
            mimetype="application/json",
        )